const raw = $json.body ?? $json;
const urls = raw.urls ?? [];

return urls.map((startUrl) => ({
  json: {
    jobId: raw.jobId,
    startUrl,
    fields: raw.fields ?? [],
    directions: raw.prompt ?? '',
    summarizePrompt: raw.summarizePrompt ?? '',
    fieldPrompt: raw.fieldPrompt ?? '',
    localLlmModel: raw.localLlmModel ?? 'gemma4:e4b',
    scraperBaseUrl: raw.scraperBaseUrl ?? 'http://simple-scraper:3000',
    totalUrls: urls.length,
  },
}));

const ctx = $('Split URLs').item.json;
const pages = $json.pages ?? [];
return [{
  json: {
    ...ctx,
    pages,
    pageCount: pages.length,
  },
}];

const config = $('After Spider').first().json;
const requestedFields = config.fields ?? [];
return [{
  json: {
    jobId: config.jobId,
    startUrl: config.startUrl,
    requestedFields,
    findings: [],
    pageResults: [],
    directions: config.directions,
    summarizePrompt: config.summarizePrompt,
    fieldPrompt: config.fieldPrompt,
    localLlmModel: config.localLlmModel,
    scraperBaseUrl: config.scraperBaseUrl,
    emptySite: true,
  },
}];

const config = $('After Spider').first().json;
const pages = config.pages ?? [];

return pages.map((pageUrl) => ({
  json: {
    jobId: config.jobId,
    startUrl: config.startUrl,
    pageUrl,
    fields: config.fields,
    directions: config.directions,
    summarizePrompt: config.summarizePrompt,
    fieldPrompt: config.fieldPrompt,
    localLlmModel: config.localLlmModel,
    scraperBaseUrl: config.scraperBaseUrl,
  },
}));

const config = $('Split Pages').item.json;
return [{
  json: {
    ...config,
    text: $json.text,
    textLength: $json.textLength,
  },
}];

const config = $('Attach Summary').item.json;
return [{
  json: {
    ...config,
    summary: $json.summary,
    summaryLength: $json.summaryLength,
  },
}];

const page = $json;
const fields = page.fields ?? [];

return fields.map((field) => ({
  json: {
    jobId: page.jobId,
    startUrl: page.startUrl,
    pageUrl: page.pageUrl,
    summary: page.summary,
    field,
    directions: page.directions,
    summarizePrompt: page.summarizePrompt,
    fieldPrompt: page.fieldPrompt,
    localLlmModel: page.localLlmModel,
    scraperBaseUrl: page.scraperBaseUrl,
  },
}));

const items = $input.all().map((item) => item.json);
const config = $('After Spider').first()?.json ?? items[0] ?? {};
const requestedFields = config.fields ?? [];

if (items.length === 0) {
  return [{
    json: {
      jobId: config.jobId,
      startUrl: config.startUrl,
      requestedFields,
      findings: [],
      pageResults: [],
      directions: config.directions,
      summarizePrompt: config.summarizePrompt,
      fieldPrompt: config.fieldPrompt,
      localLlmModel: config.localLlmModel,
      scraperBaseUrl: config.scraperBaseUrl,
      emptySite: true,
    },
  }];
}

const findings = [];
const byPage = new Map();

for (const item of items) {
  if (!byPage.has(item.pageUrl)) {
    byPage.set(item.pageUrl, {
      pageUrl: item.pageUrl,
      summary: item.summary,
      fields: [],
    });
  }
  const present = item.present === true;
  byPage.get(item.pageUrl).fields.push({
    field: item.field,
    value: present ? item.value : null,
    confidence: item.confidence ?? 'unknown',
    sourcePages: present ? [item.pageUrl] : [],
  });
  if (present) {
    findings.push({
      field: item.field,
      value: String(item.value),
      pageUrl: item.pageUrl,
      confidence: item.confidence,
    });
  }
}

const first = items[0];
return [{
  json: {
    jobId: first.jobId,
    startUrl: first.startUrl,
    requestedFields,
    findings,
    pageResults: Array.from(byPage.values()),
    directions: first.directions,
    summarizePrompt: first.summarizePrompt,
    fieldPrompt: first.fieldPrompt,
    localLlmModel: first.localLlmModel,
    scraperBaseUrl: first.scraperBaseUrl,
    emptySite: false,
  },
}];

const saved = $json;
const source = $('Aggregate Results').first()?.json ?? $('Prepare Empty Save').first()?.json ?? $('After Spider').first()?.json;
const emptySite = Boolean(source?.emptySite);
return [{
  json: {
    jobId: source.jobId,
    scraperBaseUrl: source.scraperBaseUrl,
    startUrl: source.startUrl,
    outputPath: saved.outputPath,
    message: emptySite ? 'No pages scraped for ' + source.startUrl : 'Saved output to ' + saved.outputPath,
    level: emptySite ? 'warn' : 'success',
  },
}];
